function createWrapper(transport: ReturnType<typeof createMockTransport>) {
  const queryClient = new QueryClient({
    defaultOptions: { queries: { retry: false, gcTime: 0 } },
  });
  return ({ children }: { children: React.ReactNode }) => (
    <QueryClientProvider client={queryClient}>
      <TransportProvider transport={transport}>{children}</TransportProvider>
    </QueryClientProvider>
  );
}

describe('useTaskState — sessionId guard', () => {
  beforeEach(() => {
    vi.clearAllMocks();
  });

  it('does not call transport.getTasks when sessionId is null', async () => {
    // Purpose: verify the enabled guard prevents API calls with empty session ID.
    // This is the exact bug: API was called with '' causing 400 errors because
    // ChatPanel was coercing null to '' with (sessionId ?? '').
    const mockTransport = createMockTransport();

    renderHook(() => useTaskState(null), {
      wrapper: createWrapper(mockTransport),
    });

    // Wait a tick to ensure any queries would have fired
    await new Promise((r) => setTimeout(r, 50));

    expect(mockTransport.getTasks).not.toHaveBeenCalled();
  });

  it('calls transport.getTasks when sessionId is provided', async () => {
    // Purpose: confirm the guard does not over-suppress legitimate queries.
    const mockTransport = createMockTransport({
      getTasks: vi.fn().mockResolvedValue({ tasks: [] }),
    });

    renderHook(() => useTaskState('session-123'), {
      wrapper: createWrapper(mockTransport),
    });

    await waitFor(() => {
      expect(mockTransport.getTasks).toHaveBeenCalledWith('session-123', '/test/cwd');
    });
  });

  it('returns empty tasks when sessionId is null', () => {
    // Purpose: confirm the hook returns a stable empty state when disabled.
    const mockTransport = createMockTransport();

    const { result } = renderHook(() => useTaskState(null), {
      wrapper: createWrapper(mockTransport),
    });

    expect(result.current.tasks).toEqual([]);
    expect(result.current.activeForm).toBeNull();
  });
});
